// ═══════════════════════════════════════════════════════════════
// PATCH: Troca logo do topo + zoom ao clicar em ambas as logos
// Aplique este código no final do seu app.js, ou dentro de um
// DOMContentLoaded se preferir.
// ═══════════════════════════════════════════════════════════════

(function patchLogos() {

  // ── 1. URL da nova logo (a imagem que você enviou) ─────────────
  //    Em produção, substitua pelo URL do Firebase Storage:
  //    const NOVA_LOGO = 'https://firebasestorage.googleapis.com/...';
  //
  //    Para facilitar o teste, deixamos em base64 abaixo.
  //    Se preferir hospedar no Firebase Storage:
  //      1. Faça upload de logo_acima.jpg no Storage
  //      2. Copie o download URL e cole aqui
  const NOVA_LOGO = 'data:image/jpeg;base64,';

  // ── 2. Estilos de zoom ao clicar ───────────────────────────────
  const style = document.createElement('style');
  style.textContent = `
    /* Overlay de zoom para logos */
    #logo-zoom-overlay {
      display: none;
      position: fixed;
      inset: 0;
      background: rgba(0,0,0,.75);
      z-index: 99999;
      align-items: center;
      justify-content: center;
      cursor: zoom-out;
      backdrop-filter: blur(4px);
    }
    #logo-zoom-overlay.open {
      display: flex;
    }
    #logo-zoom-overlay img {
      max-width: min(90vw, 520px);
      max-height: 80vh;
      border-radius: 16px;
      box-shadow: 0 24px 64px rgba(0,0,0,.5);
      animation: logo-pop .22s cubic-bezier(.34,1.56,.64,1);
    }
    @keyframes logo-pop {
      from { transform: scale(.7); opacity: 0; }
      to   { transform: scale(1);  opacity: 1; }
    }
    /* Deixa logos com cursor de zoom */
    .edena-logo-clickable {
      cursor: zoom-in !important;
      transition: transform .18s, box-shadow .18s;
    }
    .edena-logo-clickable:hover {
      transform: scale(1.06);
      filter: drop-shadow(0 4px 12px rgba(0,0,0,.18));
    }
  `;
  document.head.appendChild(style);

  // ── 3. Cria overlay de zoom ────────────────────────────────────
  const overlay = document.createElement('div');
  overlay.id = 'logo-zoom-overlay';
  overlay.setAttribute('role', 'dialog');
  overlay.setAttribute('aria-label', 'Logo ampliada');
  const zoomImg = document.createElement('img');
  zoomImg.alt = 'EDENA logo ampliada';
  overlay.appendChild(zoomImg);
  document.body.appendChild(overlay);

  function abrirZoom(src) {
    zoomImg.src = src;
    overlay.classList.add('open');
    document.body.style.overflow = 'hidden';
  }
  function fecharZoom() {
    overlay.classList.remove('open');
    document.body.style.overflow = '';
  }
  overlay.addEventListener('click', fecharZoom);
  document.addEventListener('keydown', e => { if (e.key === 'Escape') fecharZoom(); });

  // ── 4. Helper: aplica zoom-click a um elemento de logo ─────────
  function tornarClicavel(el, src) {
    el.classList.add('edena-logo-clickable');
    el.addEventListener('click', (e) => { e.stopPropagation(); abrirZoom(src); });
  }

  // ── 5. Troca a logo do topo (navbar / hero) ────────────────────
  //    Busca todos os <img> do header/navbar que tenham "logo" na
  //    classe, id, alt ou src. Ajuste o seletor se necessário.
  function patchLogoTopo() {
    // Seletores comuns — ajuste ao seu HTML se precisar:
    const selectors = [
      'header img',
      'nav img',
      '.navbar img',
      '.nav-logo',
      '.site-logo',
      '.logo img',
      '#logo img',
      '[class*="logo"] img',
      '[id*="logo"] img',
    ];

    let found = false;
    for (const sel of selectors) {
      const imgs = document.querySelectorAll(sel);
      imgs.forEach(img => {
        // Troca apenas logos (evita ícones pequenos)
        const w = img.naturalWidth || img.width || img.offsetWidth;
        if (w > 30 || img.alt?.toLowerCase().includes('logo') || img.src?.includes('logo')) {
          img.src = NOVA_LOGO;
          img.style.cssText += ';object-fit:contain;';
          tornarClicavel(img, NOVA_LOGO);
          found = true;
        }
      });
      if (found) break;
    }

    if (!found) {
      console.warn('[EDENA patch] Logo do topo não encontrada automaticamente.');
      console.warn('Adicione a classe "edena-logo-top" ao <img> da logo no topo e execute:');
      console.warn('document.querySelector(".edena-logo-top").src = NOVA_LOGO;');
    }
  }

  // ── 6. Torna clicável a logo do login/modal ────────────────────
  function patchLogoLogin() {
    const selectors = [
      '.login-box img',
      '.login-logo',
      '#login-overlay img',
      '.auth-logo',
      '.modal-logo',
    ];
    for (const sel of selectors) {
      document.querySelectorAll(sel).forEach(img => {
        tornarClicavel(img, img.src);
      });
    }
  }

  // ── 7. Executa ─────────────────────────────────────────────────
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => {
      patchLogoTopo();
      patchLogoLogin();
    });
  } else {
    patchLogoTopo();
    patchLogoLogin();
  }

  // Reaplica quando o login modal abrir (caso a logo seja injetada dinamicamente)
  const _origAbrirLogin = window.abrirLogin;
  if (_origAbrirLogin) {
    window.abrirLogin = function(...args) {
      _origAbrirLogin.apply(this, args);
      setTimeout(patchLogoLogin, 100);
    };
  }

})();
